import{_ as a,o as t,c as r,ag as n}from"./chunks/framework.CbHyKbeV.js";const h=JSON.parse('{"title":"Critical Rendering Path","description":"","frontmatter":{"title":"Critical Rendering Path","date":"2020-09-25T00:00:00.000Z"},"headers":[],"relativePath":"posts/2020-09-25-critical-rendering-path.md","filePath":"posts/2020-09-25-critical-rendering-path.md"}'),p={name:"posts/2020-09-25-critical-rendering-path.md"};function i(s,e,o,l,c,d){return t(),r("div",null,[...e[0]||(e[0]=[n('<p>Critical Rendering Path это последовательность шагов по превращению браузером HTML, CSS и JavaScript в пиксели на экране.</p><p>Итак, браузер получает на обработку HTML-файл. Парсер проходит его байт за байтом и вычленяет токены (самые главные - startTag, endTag), потом из набора токенов строятся ноды, а из иерархии нод получается Document Object Model (DOM) на основе информации о последовательности токенов. В DOM содержится весь контент страницы.</p><p>Когда парсер находит токены запросов внешних ресурсов (стилей, картинок, скриптов), он их запрашивает, но от 4 до 7 за раз в зависимости от браузера. Некоторые запросы блокируют парсинг, некоторые могут идти в параллели.</p><p>Когда парсер видит токен стилей, он начинает строить CSS Object Model (CSSOM). Оно строится очень быстро, поэтому оптимизация CSS-селекторов не даёт большого прироста к производительности, а минификация и отложенный запрос второстепенных стилей - даёт. Когда DOM и CSSOM готовы, начинается создание Render Tree.</p><p>Render Tree содержит в себе весь контент и его стилизацию. Кроме явно скрытых (display:none) элементов.</p><p>Эти три фазы, как правило,происходят один раз, но возможны ситуации когда свежезагруженный скрипт основательно меняет DOM (размеры элементов, отступы), тогда этот процесс происходит заново.</p><p>На основе Render Tree строится Layout - расположение элементов друг относительно друга и размеры блоков на основе их содержимого. Нужно помнить, что изменение размеров окна браузера, поворот смартфона, а и иногда и обычный запрос из скрипта расстояния между элементами может привести к пересчёту всего Layout. Чем больше DOM, тем больше занимает время пересчёт Layout (reflow). В это время страница не может реагировать на действия пользователя. Желательно что бы reflow занимал максимум 10 миллисекунд чтобы добиться 60 кадров в секунду.</p><p>Следующий шаг - Paint. Обычно он не доставляет хлопот в оптимизации, он просто растеризует (превращает в пиксели с помощью GPU) то, что насчиталось в Layout. Paint происходит в несколько слоёв в зависимости от позиционирования элементов. Проблемы с ним бывают при работе со сложной анимацией в canvas, они решаются отрисовкой в памяти, &quot;за экраном&quot; с помощью OffScreenCanvas или WebWorker-ов.</p><p>Поскольку отрисовка многослойная, мы получаем возможность двигать элементы не вызывая Paint снова. Пока только два стиля - opacity и transition - работают на этом этапе. Указать парсеру что элемент будет двигаться можно заранее с помощью</p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">will-change</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: transform;</span></span></code></pre></div><p>но не нужно делать этого повсеместно чтобы не нагружать GPU.</p><p>Поскольку браузер - основная платформа веб-разработчиков, непонимание вышеописанного процесса ведёт к созданию неотзывчивых сайтов.</p><p>Секунды задержки в интернет-магазинах приводят к миллионам недополученной прибыли. А из-за отсутствия при старте проекта требований к производительности, веб-приложение для гос-служащих с 15Мб скриптов на Камчатке грузится 38 минут.</p><p>Источники:</p><p>Личный опыт</p><p><a href="https://developers.google.com/web/fundamentals/performance/rendering" target="_blank" rel="noreferrer">https://developers.google.com/web/fundamentals/performance/rendering</a></p><p><a href="https://developer.mozilla.org/en-US/docs/Web/Performance/Critical_rendering_path" target="_blank" rel="noreferrer">https://developer.mozilla.org/en-US/docs/Web/Performance/Critical_rendering_path</a></p>',17)])])}const _=a(p,[["render",i]]);export{h as __pageData,_ as default};
